PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE programmes (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  nom TEXT NOT NULL UNIQUE,
  commune TEXT NOT NULL DEFAULT '',
  cp TEXT DEFAULT '',
  adresse TEXT DEFAULT '',
  statut TEXT DEFAULT 'En commercialisation',
  reglementation TEXT DEFAULT 'RE2020',
  livraison TEXT DEFAULT '',
  livraison_detail TEXT DEFAULT '',
  debut_travaux TEXT DEFAULT '',
  lots_total INTEGER DEFAULT 0,
  pieces TEXT DEFAULT '',
  surface_min REAL DEFAULT 0,
  surface_max REAL DEFAULT 0,
  prix_min INTEGER DEFAULT 0,
  prix_max INTEGER DEFAULT 0,
  eligibilites TEXT DEFAULT '',
  plan3d TEXT DEFAULT '',
  youtube TEXT DEFAULT '',
  img_cover TEXT DEFAULT '',
  photos TEXT DEFAULT '[]',
  desc_courte TEXT DEFAULT '',
  desc_longue TEXT DEFAULT '',
  atouts TEXT DEFAULT '[]',
  prestations TEXT DEFAULT '[]',
  timeline TEXT DEFAULT '[]',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE lots (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  programme_nom TEXT NOT NULL,
  num TEXT NOT NULL,
  etage TEXT DEFAULT '',
  typo TEXT DEFAULT '',
  surface REAL DEFAULT 0,
  prix INTEGER DEFAULT 0,
  statut TEXT DEFAULT 'Disponible',
  acquereur TEXT DEFAULT '',
  plan3d INTEGER DEFAULT 0,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now')),
  UNIQUE(programme_nom, num)
);
CREATE TABLE leads (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  prenom TEXT DEFAULT '',
  nom TEXT NOT NULL,
  programme TEXT DEFAULT '',
  typo TEXT DEFAULT '',
  budget TEXT DEFAULT '',
  statut TEXT DEFAULT 'Premier contact',
  source TEXT DEFAULT '',
  priorite TEXT DEFAULT 'l',
  email TEXT DEFAULT '',
  telephone TEXT DEFAULT '',
  notes TEXT DEFAULT '',
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE settings (
  key TEXT PRIMARY KEY,
  value TEXT NOT NULL,
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE knowledge_base (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  categorie TEXT NOT NULL,
  titre TEXT NOT NULL,
  contenu TEXT NOT NULL,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE pdf_documents (
  id           INTEGER PRIMARY KEY AUTOINCREMENT,
  programme_id INTEGER,
  programme_nom TEXT NOT NULL DEFAULT '',
  doc_type     TEXT NOT NULL,
  filename     TEXT NOT NULL,
  file_size_kb INTEGER DEFAULT 0,
  status       TEXT NOT NULL DEFAULT 'pending',
  error_msg    TEXT DEFAULT '',
  page_count   INTEGER DEFAULT 0,
  chunk_count  INTEGER DEFAULT 0,
  ingested_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at   DATETIME DEFAULT CURRENT_TIMESTAMP
, r2_key TEXT);
CREATE TABLE pdf_chunks (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  document_id   INTEGER NOT NULL,
  programme_id  INTEGER,
  programme_nom TEXT NOT NULL DEFAULT '',
  doc_type      TEXT NOT NULL DEFAULT '',
  chunk_index   INTEGER NOT NULL DEFAULT 0,
  chunk_text    TEXT NOT NULL,
  vectorize_id  TEXT NOT NULL DEFAULT '',
  metadata_json TEXT DEFAULT '{}',
  created_at    DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE pdf_structured (
  id            INTEGER PRIMARY KEY AUTOINCREMENT,
  document_id   INTEGER NOT NULL,
  programme_id  INTEGER,
  doc_type      TEXT NOT NULL DEFAULT '',
  extracted_json TEXT NOT NULL DEFAULT '{}',
  extracted_at  DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE acquereurs (id INTEGER PRIMARY KEY AUTOINCREMENT, programme_nom TEXT NOT NULL, lot_num TEXT NOT NULL, nom TEXT NOT NULL DEFAULT '', email TEXT DEFAULT '', telephone TEXT DEFAULT '', date_reservation TEXT DEFAULT '', notes TEXT DEFAULT '', created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), prenom TEXT DEFAULT '', statut TEXT DEFAULT 'Réservé', date_acte TEXT DEFAULT '', date_livraison TEXT DEFAULT '', UNIQUE(programme_nom, lot_num));
CREATE TABLE users (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  nom TEXT NOT NULL,
  email TEXT NOT NULL UNIQUE,
  password_hash TEXT NOT NULL,
  role TEXT NOT NULL DEFAULT 'editeur',
  actif INTEGER NOT NULL DEFAULT 1,
  last_login TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE sessions (
  id TEXT PRIMARY KEY,
  user_id INTEGER NOT NULL,
  created_at TEXT DEFAULT (datetime('now')),
  expires_at TEXT NOT NULL
);
CREATE TABLE login_attempts (
  email TEXT PRIMARY KEY,
  attempts INTEGER DEFAULT 0,
  locked_until TEXT
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_pdfchunks_document  ON pdf_chunks(document_id);
CREATE INDEX idx_pdfchunks_programme ON pdf_chunks(programme_id);
CREATE INDEX idx_pdfchunks_vectorize ON pdf_chunks(vectorize_id);
CREATE INDEX idx_pdfstruct_document  ON pdf_structured(document_id);
CREATE INDEX idx_pdfstruct_programme ON pdf_structured(programme_id);
CREATE UNIQUE INDEX idx_pdf_documents_r2_key ON pdf_documents(r2_key);
