INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(1,'programme','rive_azure_general',replace('PROGRAMME : RIVE AZURE — MALROY\nAdresse : 44 rue Principale, 57640 Malroy\nPromoteur : G2O-P G2O PARTICIPATION / Maison & Habitat FREEHOME\nSCCV porteuse : SCCV AZURE (SIREN 952 676 617)\nPermis de construire : n°505743823M0003, délivré le 21/07/2023 par la commune de Malroy\nMise à jour notice : 08/09/2023\n\nDESCRIPTION GÉNÉRALE :\nImmeuble de type R+1 + combles aménagés, comportant 5 logements répartis sur 2 niveaux.\nRéglementation thermique RE 2020. Conforme réglementation acoustique et accessibilité PMR.\nHauteur sous plafond : 2,50 m minimum (hors retombées techniques).\n\nCOMPOSITION DU PROGRAMME :\n- LOT 101 : T3 — 80,12 m² hab. + 26 m² jardin + 17,38 m² terrasse/loggia — Prix affiché 329 000 € — VENDU/LIVRÉ\n- LOT 102 : T1 — 19,59 m² hab. + 15 m² jardin — Prix affiché 88 900 € — RÉSERVÉ le 24/02/2026\n- LOT 103 : T3 — 71,86 m² hab. + 15 m² jardin + 17,38 m² terrasse/loggia — Prix affiché 295 000 € — VENDU/LIVRÉ\n- LOT 202 : T2 — 56,21 m² hab. + 24 m² jardin + 13,64 m² loggia — Prix affiché 234 900 € — VENDU (livraison prévue 28/02/2026)\n- LOT 201 : T3 — 68,44 m² hab. + 24 m² jardin + 13,64 m² loggia — Prix affiché 282 000 € — RÉSERVÉ le 20/02/2026\n\nTaux de commercialisation : 98% — Programme quasi sold-out.\nBase de calcul prix : 3 800 €/m²\n\nSTATIONNEMENT :\nParkings couverts intérieurs : places n°09 à 13, 18 et 22\nParkings extérieurs : places n°07, 08, et 28 à 33\nCave attribuée à chaque appartement.\nPré-équipement recharge véhicule électrique prévu à chaque place.','\n',char(10)),'2026-02-24 13:34:51');
INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(2,'programme','rive_azure_finitions',replace('RIVE AZURE — FINITIONS ET ÉQUIPEMENTS PRIVATIFS\n\nSOLS (pièces principales : entrée, séjour, chambres, dégagements) :\nAu choix de l''acquéreur :\n- Carrelage 60×60 gamme Habitat 2023 ANZILE (ou équivalent), coloris au choix dans la gamme\n- Carrelage 45×45 gamme Habitat 2023 ANZILE (ou équivalent), coloris au choix dans la gamme\n- Parquet stratifié à chanfrein gamme EXTREME AQUA de SPE ou Swiss Krono ADVANCED, coloris au choix\nPlinthes : carrelage assorti (si carrelage) ou blanches peintes (si parquet)\n\nSOLS (pièces de service : WC, SDB, SDE, cuisine) :\nIdentique pièces principales pour carrelage. Parquet autorisé en cuisine uniquement (désolidarisé des meubles).\n\nREVÊTEMENTS MURAUX (salles de bains et salles d''eau) :\n- Faïence 50×25 ANZILE, toute hauteur au droit douche/baignoire + pan adjacent\n- Faïence 50×25 ANZILE, hauteur 60 cm au-dessus meuble vasque\n- Harmonies prédéfinies par le Maître d''ouvrage, choix dans la gamme\n- Options : faïence sur pans de murs restants\n\nPEINTURES INTÉRIEURES :\n- Murs pièces sèches : 2 couches peinture blanc velours, finition B\n- Murs pièces humides : 2 couches peinture blanche satinée\n- Plafonds pièces sèches : 2 couches blanc mat aspect lisse\n- Plafonds pièces humides et cuisine ouverte : 2 couches blanche satinée\n- Menuiseries bois et huisseries : 2 couches peinture blanche satinée\n\nMENUISERIES INTÉRIEURES :\n- Portes intérieures : modèle ALBA de MOSEL TÜREN, âme tubulaire, structure MDF, finition laqué blanc — chambranle/contre-chambranle\n- Quincaillerie : béquilles sur plaque avec condamnation à verrou (WC/SDB/SDE), clé en L ou I (chambres), bec de cane (autres pièces)\n- Porte palière : bloc-porte antieffraction A2P BP1, serrure 3 points VACHETTE V5 code N1, coloris "fruitier cendré", avec microviseur\n- Placards : façade coulissante mélaminé blanc 10mm profil acier (ou panneau pliant PVC si largeur < 80cm) pour le placard d''entrée. Autres placards : sans façade ni aménagement intérieur.\n\nMENUISERIES EXTÉRIEURES :\n- Gamme 82 SOFTLINE VEKA, PVC coloris RAL 7039 Gris Quartz extérieur / blanc intérieur\n- Double ou triple vitrage selon étude thermique (triple vitrage 4/18/4/18/4 = 48mm)\n- Mécanisme oscillo-battant, micro-ventilation dans le vantail, ferrure anti-fausse manœuvre, gâche antieffraction, galet octogonal\n- Vitrage granité pour SDB/SDE/WC (tous niveaux)\n- Volets roulants aluminium isolants motorisés radio (commande Smoove Origin I/O) sur toutes pièces principales et cuisines — coffre "invisible" intégré dans le mur\n- Porte de garage sectionnelle motorisée, paroi isolée 40mm acier laqué, coloris coordonné menuiseries','\n',char(10)),'2026-02-24 13:35:29');
INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(3,'programme','rive_azure_equipements',replace('RIVE AZURE — ÉQUIPEMENTS TECHNIQUES ET SANITAIRES\n\nCHAUFFAGE ET EAU CHAUDE :\n- Pompe à chaleur air/eau bi-bloc Loria Duo R32 4kW\n- Plancher chauffant hydraulique (rayonnant) dans toutes les pièces de vie et circulations\n- Production eau chaude sanitaire par ballon thermodynamique ou PAC combinée\n- Thermostat régulation : 1 thermostat pièce principale (T1/T2) + 1 thermostat zone nuit (T3/T4)\n- SDB/SDE : sèche-serviette CARRERA SATURNE, sec tubes ronds 500W + soufflerie 1000W, avec miroir et thermostat programmable, coloris blanc\n- VMC simple flux hygro B individuelle — bouches d''extraction dans pièces humides, prises d''air en menuiseries ou maçonneries\n\nSANITAIRES (marque CREAZUR, fabricant français) :\n- Receveur de douche résine gelcoaté 25mm, encastré (ressaut max 2cm)\n- Paroi de douche verre 8mm, 80 à 120cm, avec ou sans retour\n- Colonne de douche thermostatique KONFOR (CREAZUR) avec ciel de douche, douchette et flexible\n- Mitigeur vasque KONFOR (CREAZUR), cartouche avec limiteur de débit\n- Meuble vasque PMR LEA (CREAZUR), profondeur 70 à 90cm, simple vasque, coloris au choix — livré sans coffre armoire\n  Options : double vasque, coffre roulette, armoire coordonnée\n- WC suspendu VITRA S20 avec réservoir encastré (ou WC à poser VITRA S20 avec réservoir encastré si mur insuffisant)\n- Lave-mains : meuble LILA simple vasque 26cm coloris OAK ou blanc, ou vasque angle RESIANGLE PMR (T1/T2 uniquement selon plan)\n\nPLOMBERIE :\n- Distribution eau froide : colonne PVC pression + canalisations PER sous dalle\n- Eau chaude individuelle : canalisations PER\n- VMC, ballons thermodynamiques : gaine commune évacuation en toiture ou façade\n- Branchements en attente : lave-linge + lave-vaisselle (T3+), lave-linge seul (T1/T2)\n- Toutes salles d''eau adaptables PMR\n\nÉLECTRICITÉ (gamme DOOXIE LEGRAND, coloris blanc) :\n- Tableau d''abonné + disjoncteur général en GTL dans l''entrée\n- Commandes volets : radio SMOOVE ORIGIN I/O (à piles, positionnement libre)\n- Commandes éclairage : filaires DOOXIE LEGRAND blanc\n- Prises RJ45 dans séjour et chambres, coffret communication en GTL\n- Puissance : 6 à 18 kW selon logement\n- Détecteur de fumée DAAF dans dégagement ou entrée\n- Prise recharge VE en option sur parking intérieur (raccordement compteur appartement)\n- Pré-câblage VIGIK + visiophone BTICINO Class 100 V12E écran couleur\n\nCUISINE :\n- Livrée sans meubles, arrivées eau chaude/froide et évacuation en attente\n- En option : kitchenette (évier inox 2 cuves + égouttoir sur meuble blanc 2 portes + crédence faïence 60cm) à la charge de l''acquéreur\n\nTÉLÉCOMS :\n- Raccordement fibre optique si disponible au droit de l''opération à la livraison\n- Prises RJ45 câblées vers coffret communication GTL logement\n\nCATALOGUE RÉFÉRENTIEL ÉQUIPEMENTS : disponible sur demande auprès du conseiller commercial','\n',char(10)),'2026-02-24 13:36:13');
INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(4,'vefa','vefa_processus',replace('PROCESSUS D''ACHAT EN VEFA (Vente en l''État Futur d''Achèvement)\n\nQU''EST-CE QUE LA VEFA ?\nLa VEFA est le cadre légal de la promotion immobilière neuve en France (articles L.261-1 et suivants du Code de la Construction et de l''Habitation). L''acquéreur achète un bien qui n''est pas encore construit ou en cours de construction. Le vendeur légal est la SCCV (Société Civile de Construction-Vente) dédiée au programme.\n\nLES GRANDES ÉTAPES :\n\n1. RÉSERVATION (avant-contrat)\n- Signature du Contrat de Réservation entre l''acquéreur et la SCCV\n- Versement d''un dépôt de garantie sur compte séquestre :\n  • 5% du prix si acte authentique prévu dans moins d''1 an\n  • 2% si délai entre 1 et 2 ans\n  • 0% si délai supérieur à 2 ans\n- Délai de rétractation légal de 10 jours calendaires (art. L.271-1 CCH) à compter du lendemain de la 1ère présentation du courrier recommandé — sans motif, sans pénalité, remboursement sous 21 jours\n\n2. FINANCEMENT\n- L''acquéreur dispose en général de 45 à 90 jours pour obtenir son prêt immobilier\n- Condition suspensive légale : si le prêt est refusé, le contrat est résolu et le dépôt restitué intégralement\n\n3. ACTE AUTHENTIQUE DE VENTE\n- Signé chez le notaire (l''acquéreur peut avoir son propre notaire sans frais supplémentaires)\n- Frais de notaire réduits en VEFA : environ 2 à 3% (vs 7 à 8% dans l''ancien), car calculés sur le prix HT du terrain\n\n4. APPELS DE FONDS (plafonds légaux — art. R.261-14 CCH)\n- 35% à l''achèvement des fondations\n- 70% à la mise hors d''eau (toiture)\n- 95% à l''achèvement de l''immeuble\n- 5% à la remise des clés (livraison)\n\n5. LIVRAISON ET REMISE DES CLÉS\n- Procès-verbal de livraison contradictoire\n- L''acquéreur a 1 mois pour signaler les réserves non apparentes lors de la remise des clés\n- Les dates de livraison sont des estimations pouvant évoluer pour raisons techniques ou administratives\n\nGARANTIES OBLIGATOIRES :\n- Garantie Financière d''Achèvement (GFA) extrinsèque : assure l''achèvement du programme en cas de défaillance du promoteur — obligatoire pour tous les programmes FREEHOME\n- Garantie de parfait achèvement (1 an) : tous désordres signalés dans l''année suivant la livraison\n- Garantie biennale (2 ans) : éléments d''équipement dissociables (volets, robinetterie, chauffe-eau...)\n- Garantie décennale (10 ans) : désordres affectant la solidité ou rendant le bien impropre à sa destination\n\nDISPOSITIFS FISCAUX POSSIBLES (selon éligibilité programme et acquéreur) :\n- PTZ (Prêt à Taux Zéro) : primo-accédants, sous conditions de ressources et de zone\n- TVA réduite 5,5% : zones ANRU ou QPV, sous conditions\n- LMNP (Loueur Meublé Non Professionnel) : investissement locatif meublé\n- Dispositif Pinel : fin du dispositif classique, vérifier éligibilité selon date de PC\nNote : FREEHOME ne garantit pas l''éligibilité personnelle aux dispositifs fiscaux — recommande consultation d''un conseiller fiscal','\n',char(10)),'2026-02-24 13:36:54');
INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(5,'vefa','vefa_choix_personnalisation',replace('PERSONNALISATION ET CHOIX ACQUÉREURS EN VEFA\n\nPRINCIPE GÉNÉRAL :\nEn VEFA, l''acquéreur peut personnaliser son logement dans les limites définies par le Maître d''Ouvrage, et uniquement avant certaines étapes de chantier. Passé ces délais, les modifications ne sont plus possibles.\n\nCHOIX PROPOSÉS PAR FREEHOME (valable pour Rive Azure, à confirmer par programme) :\n- Revêtements de sol : choix du coloris carrelage (format 60×60 ou 45×45 gamme ANZILE) ou parquet stratifié (gammes EXTREME AQUA SPE ou Swiss Krono ADVANCED)\n- Faïence salle de bain : choix dans les harmonies prédéfinies (format 50×25 ANZILE)\n- Le catalogue de choix détaillé est fourni au cours de l''évolution des travaux\n\nOPTIONS PAYANTES POSSIBLES :\n- Faïence supplémentaire sur pans de murs restants en SDB/SDE\n- Double vasque, coffre de rangement, armoire coordonnée (salle de bain)\n- Kitchenette / évier cuisine (livré sans meubles par défaut)\n- Adaptation PMR des salles d''eau (équipements supplémentaires)\n- Raccordement prise VE au compteur appartement (parking intérieur)\n- Modification couleur plinthes (peinture assortie aux murs)\n- Adaptation arrivées eau/évacuation aux plans personnalisés cuisiniste\n\nDÉLAIS IMPORTANTS :\nLes choix de finitions doivent être faits avant les étapes chantier correspondantes (pose carrelage, faïence, etc.). Passé ce délai, les travaux sont déjà réalisés avec les options par défaut.\n\nVISUELS NON CONTRACTUELS :\nTous les visuels 3D, plans et perspectives présentés sont des représentations artistiques indicatives. Les caractéristiques définitives sont celles de la Notice Descriptive annexée au Contrat de Réservation et à l''Acte Authentique.','\n',char(10)),'2026-02-24 13:37:19');
INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(6,'programme','clos_prevert_general',replace('PROGRAMME CLOS PREVERT — Ay-sur-Moselle (57300)\nAdresse : 56 rue de Thionville, 57300 Ay-sur-Moselle\nSCCV : SCCV CLOS PREVERT — SIREN 941 742 918 — RCS Metz\nPermis de construire : n°05704323M0005 délivré le 18/01/2024\nRéglementation : RE 2020\nLivraison estimée : T3 2026\n\nCOMPOSITION :\n- 3 bâtiments identiques (A, B, C) de type R+1+combles\n- 45 logements au total (15 par bâtiment)\n- Ascenseur PMR dans chaque bâtiment\n- Parking sous-terrain commun : 45 places (1 par logement, incluse)\n- Caves individuelles en sous-sol, attenantes à chaque place de parking (incluses)\n- 1 place de parking extérieur par logement (incluse)\nIMPORTANT : chaque lot inclut par défaut 3 annexes : place parking sous-terrain + cave attenante + place parking extérieur. Ces annexes sont comprises dans le prix affiché.\n\nRÉPARTITION PAR ÉTAGE (identique pour chaque bâtiment A, B, C) :\nRDC (6 lots par bâtiment) :\n  - x01 : T2 57.91m² + balcon/terr 12.75m² + jardin 15m² → 234 900€\n  - x02 : T4 78.58m² + balcon/terr 12.79m² + jardin 15m² → 299 900€\n  - x03 : T2 55.27m² + balcon/terr 12.87m² + jardin 15m² → 229 000€\n  - x04 : T4 83.72m² + balcon/terr 12.88m² + jardin 15m² → 319 900€\n  - x05 : T3 61.83m² + balcon/terr 23.00m² + jardin 10m² → 254 000€\n  - x06 : T3 66.80m² + balcon/terr 23.93m² + jardin 10m² → 269 900€\nR+1 (6 lots par bâtiment) :\n  - x11 : T2 55.39m² + balcon 2.98m² → 203 900€\n  - x12 : T4 78.01m² + balcon 6.06m² → 279 900€\n  - x13 : T2 52.68m² + balcon 3.02m² → 194 900€\n  - x14 : T4 78.50m² + balcon 6.29m² → 279 900€\n  - x15 : T3 66.80m² + balcon 7.48m² → 244 900€\n  - x16 : T3 61.96m² + balcon 7.65m² → 229 000€\nR+2/Combles (3 lots par bâtiment) :\n  - x21 : T4 92.81m² + rampant 25m² + combles 46.31m² → 379 000€\n  - x22 : T2 49.55m² + rampant 15m² + combles 37.98m² → 235 900€\n  - x23 : T4 63.50m² + rampant 25m² + combles 42.74m² → 289 900€\n\nSTATUT COMMERCIAL : Tous les 45 lots sont disponibles (aucune réservation à ce jour).\nPrix indiqués "plateau vide à décorer" (sans cuisines équipées).\n\nFOURCHETTE DE PRIX : de 194 900€ (T2 R+1) à 379 000€ (T4 combles).\nSURFACES habitables : de 49.55m² à 92.81m².\nTYPOLOGIES : T2, T3, T4.','\n',char(10)),'2026-02-24 13:58:30');
INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(7,'programme','clos_prevert_finitions',replace('CLOS PREVERT — FINITIONS ET REVETEMENTS (Notice synthétique v1 + Notice descriptive)\n\nSOLS PIECES DE VIE (séjour, cuisine, couloir, WC) :\n- Carrelage grès cérame ANZILE catalogue Habitat 2024\n- Format 60x60 cm, pose droite avec joint 2mm\n- Plinthes assorties\n\nSOLS CHAMBRES :\n- Parquet stratifié EXTREME AQUA SPE (résistant eau)\n- Option upgradable : parquet massif contre-collé (option payante)\n- Plinthes CUBU ROMUS hermétiques (anti-infiltration eau et poussières)\n\nSALLE DE BAINS / DOUCHE — 2 niveaux de choix :\nCHOIX 1 (option premium) : Carrelage grand format 120x60 cm, toute hauteur, tous murs\nCHOIX 2 (standard inclus) : Faïence 20x60 cm ou 20x40 cm sur 2 pans de murs uniquement\n\nPEINTURES :\n- Plafonds : peinture blanche satinée 2 couches\n- Murs : enduit lissé + peinture blanche satinée 2 couches\n- Faux-plafonds BA13 suspendus\n\nMENUISERIES EXTERIEURES :\n- Profil : VEKA SOFTLINE\n- Vitrage triple : 4/16/4/16/4 = 44mm (vs 48mm Rive Azure)\n- Coloris : gris quartz extérieur / blanc intérieur\n- Volets roulants motorisés SOMFY RS100 io (vs Smoove Origin I/O Rive Azure)\n- Coffres volet roulant intégrés en faux-plafond\n\nPORTE PALIERE :\n- Modèle ALBA — MOSEL TÜREN, finition fruitier cendré, serrure 3 points\n\nPORTES INTERIEURES :\n- Modèle ALBA — MOSEL TÜREN, même finition\n\nSTRUCTURE / GROS OEUVRE :\n- Maçonnerie : blocs terre cuite POROTHERM GF R20 Th+\n- Isolation thermique par extérieur (ITE)\n- Toiture : charpente traditionnelle + tuile mécanique\n\nESCALIERS COMMUNS :\n- Béton brut taloché, garde-corps métal laqué blanc','\n',char(10)),'2026-02-24 13:54:03');
INSERT INTO "knowledge_base" ("id","categorie","titre","contenu","updated_at") VALUES(8,'programme','clos_prevert_equipements',replace('CLOS PREVERT — EQUIPEMENTS ET REFERENCES TECHNIQUES (Référentiel ASM)\n\nCHAUFFAGE / CLIMATISATION :\n- Système principal : Pompe à chaleur air/eau LORIA DUO R32 (même que Rive Azure)\n- Plancher chauffant basse température dans toutes les pièces\n- Option PAC air/air réversible disponible (climatisation été — différence vs Rive Azure)\n- Sèche-serviette électrique CARRERA ARROW 500W (vs SATURNE 1500W Rive Azure)\n\nVENTILATION :\n- VMC hygro B (double flux par logement)\n\nSANITAIRES / SALLE DE BAINS :\n- Meuble vasque : LEA CREAZUR ou ROSINOX inox décor bois (au choix, vs LEA seul Rive Azure)\n- Miroir avec éclairage LED intégré\n- Baignoire / douche : CREAZUR (selon plan)\n- Douche italienne avec paroi vitrée\n- WC suspendu : VITRA S20, abattant frein de chute\n- Robinetterie : chromée standard\n- Colonne de douche thermostatique\n\nELECTRICITE / DOMOTIQUE :\n- Appareillage électrique : LEGRAND DOOXIE série complète\n- Interphone vidéo : BTICINO (visiophone couleur)\n- Pré-câblage fibre optique dans chaque logement\n- Pré-équipement borne recharge véhicule électrique (parking)\n- Tableau électrique dédié par logement\n\nASCENSEUR :\n- Ascenseur PMR dans chaque bâtiment (A, B, C) — caractéristique spécifique Clos Prévert\n\nSTATIONNEMENT ET RANGEMENTS — INCLUS PAR DÉFAUT DANS CHAQUE LOT :\n- 1 place de parking sous-terrain numérotée (incluse dans le prix)\n- 1 cave privative attenante à la place de parking sous-terrain (incluse dans le prix)\n  → La cave est physiquement dans le prolongement de la place de parking en sous-sol\n- 1 place de parking extérieur (incluse dans le prix)\nChaque acquéreur bénéficie donc de 3 annexes incluses : parking ss-terrain + cave + parking extérieur.\nDes places ou caves supplémentaires peuvent être acquises en option selon disponibilité.\n\nESPACES EXTERIEURS :\n- Jardins privatifs RDC (10 à 15m² selon lot), clos avec portillon\n- Terrasses/balcons avec garde-corps aluminium\n- Combles aménageables aux lots R+2\n\nSECURITE :\n- Digicode accès résidence\n- Contrôle accès badge communs et sous-sol\n- Serrure 3 points porte palière\n\nNORMES ET LABELS :\n- RE 2020 (réglementation thermique en vigueur)\n- Accessibilité PMR toutes parties communes\n- Ascenseur PMR chaque bâtiment\n- Pré-équipement VE (véhicule électrique)','\n',char(10)),'2026-02-24 13:57:58');
